import{_ as t,o as a,c as r,ae as o}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Doubleclick (Legacy)","description":"","frontmatter":{"title":"Doubleclick (Legacy)","slug":"doubleclick-legacy"},"headers":[],"relativePath":"marketer-hub/doubleclick-legacy.md","filePath":"marketer-hub/doubleclick-legacy.md"}'),n={name:"marketer-hub/doubleclick-legacy.md"};function i(s,e,l,c,d,h){return a(),r("div",null,[...e[0]||(e[0]=[o('<p><em>[Image: 533]</em></p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Track your <a href="https://doubleclick.com" target="_blank" rel="noreferrer"><strong>Doubleclick</strong></a> campaigns using Branch&#39;s Ads product. Branch&#39;s Ad Product will enable you to update your Doubleclick Campaign Manager (DCM) campaigns with deep links that send data back to Doubleclick&#39;s servers.</p><div class="info custom-block"><p class="custom-block-title">Doubleclick Complete Coverage</p><p>DoubleClick supports tracking links, and is also a self-attributing network with limited data in the response. Follow the relevant setup guide for the behavior you would like to see. Where possible, we recommend setting up <em>both</em> implementations for complete coverage, so data appears in Branch, the ad partner, and DoubleClick.</p><p><strong>Setup 1</strong></p><p>You can see conversion data in <em>DoubleClick Campaign Manager</em> without using any tracking links by setting up Floodlight tags. DoubleClick will be notified of all conversions.</p><p><strong>Setup 2</strong></p><p>You can see conversion data in the <em>Branch</em> dashboard by using tracking links for the ad network you are running ads with. Postbacks will be sent to the ad network.</p></div><h2 id="setup-1-seeing-data-in-doubleclick" tabindex="-1">Setup 1: Seeing data in DoubleClick <a class="header-anchor" href="#setup-1-seeing-data-in-doubleclick" aria-label="Permalink to &quot;Setup 1: Seeing data in DoubleClick&quot;">​</a></h2><h3 id="doubleclick-campaign-manager-set-up" tabindex="-1">Doubleclick Campaign Manager Set Up <a class="header-anchor" href="#doubleclick-campaign-manager-set-up" aria-label="Permalink to &quot;Doubleclick Campaign Manager Set Up&quot;">​</a></h3><p>Before we start anything on the Branch side, we need to configure options on the DCM side. Start by heading to your DCM dashboard, and navigating to the advertisers&#39; section.</p><h5 id="grab-advertiser-id" tabindex="-1">Grab Advertiser ID <a class="header-anchor" href="#grab-advertiser-id" aria-label="Permalink to &quot;Grab Advertiser ID&quot;">​</a></h5><p>First, we&#39;ll need to grab the advertiser ID. Select the advertiser you want to track, and grab the Advertiser ID. In this example, it is 6637276. This is the advertiser you will track campaigns with. Please keep note of it.</p><p><em>[Image: 534]</em></p><h5 id="grab-server-to-server-token" tabindex="-1">Grab Server to Server Token <a class="header-anchor" href="#grab-server-to-server-token" aria-label="Permalink to &quot;Grab Server to Server Token&quot;">​</a></h5><p>Once you&#39;ve captured the advertiser ID and selected the advertiser, navigate to <strong>Floodlight Configuration</strong>. From there, go to &quot;server to server&quot;, and make sure &quot;in-app attribution tracking&quot; is check-marked. Click new token, call it “Branch token”, and save it. Copy this value, as well.</p><p><em>[Image: 988]</em></p><p>Now that you have <strong>Advertiser ID</strong> and <strong>Server to Server Token</strong>, the last step is to find the events you need to track.</p><h5 id="grab-tags-for-events" tabindex="-1">Grab Tags for Events <a class="header-anchor" href="#grab-tags-for-events" aria-label="Permalink to &quot;Grab Tags for Events&quot;">​</a></h5><p>Go to the <strong>Floodlight activities</strong> tab. For all the events you want to track, grab the <strong>Activity tag String</strong> and <strong>Group tag String</strong>.</p><p><em>[Image: 1596]</em></p><p>In the above screenshot, the two values for <strong>Activity tag String</strong> are <em>act-ios</em> and <em>act-android</em>. The one value for <strong>Group tag String</strong> is <em>sales</em>. Do this for all activities you want to track.</p><p>Once you&#39;re done with this exercise, you should have at least 4 unique values:</p><ul><li>Server to Server token</li><li>Advertiser ID</li><li>Activity tag String (per event)</li><li>Group tag String (per event)</li></ul><h3 id="branch-dashboard-setup" tabindex="-1">Branch Dashboard Setup <a class="header-anchor" href="#branch-dashboard-setup" aria-label="Permalink to &quot;Branch Dashboard Setup&quot;">​</a></h3><p>Let&#39;s take these values and place them in Branch&#39;s dashboard. Begin by navigating to the <a href="https://dashboard.branch.io/ads/partner-management/a_doubleclick" target="_blank" rel="noreferrer">partners page</a>.</p><h5 id="enable" tabindex="-1">Enable <a class="header-anchor" href="#enable" aria-label="Permalink to &quot;Enable&quot;">​</a></h5><p>Find DoubleClick in the search box. Hit enable. In the <strong>Account Settings</strong> tab, insert your <strong>Server to Server token</strong>.</p><h5 id="map-events" tabindex="-1">Map Events <a class="header-anchor" href="#map-events" aria-label="Permalink to &quot;Map Events&quot;">​</a></h5><p>At this point, you have enabled Branch to communicate with Doubleclick. Now we need to map Branch events to <strong>Floodlight Activities</strong> found on the Doubleclick dashboard.</p><ol><li>Click the <strong>Postback Config</strong> tab.</li><li>Set <em>Send Postbacks For</em> to <strong>All Events</strong></li><li>You should see a URL for the event <strong>Install</strong>. For demonstration purposes, we will assume you have a corresponding Install event on the Doubleclick dashboard, but this applies to any event you add.</li><li>Start by grabbing your <strong>Advertiser ID</strong>, <strong>Activity tag String</strong>, and <strong>Group tag String</strong>.</li></ol><p>In the screenshot above, we have two events, &quot;In App Activations - Android&quot;, and &quot;In App Activations - iOS&quot;, which correspond to the Branch Install event. For this example, the <strong>Activity tag Strings</strong> are <em>act-and</em> and <em>act-ios</em>. The <strong>Group tag String</strong> is <em>sales</em>.</p><p>Copy the existing URL in Install, and replace the <em>src</em>, <em>cat</em>, and <em>type</em> variables. The &quot;cat&quot; example below has conditional iOS and Android information.</p><p>Your end result should look exactly like this, where there are different cat tags for iOS and Android.</p><p><code>https://ad.doubleclick.net/ddm/s2s/appactivity/src=6637276;cat=&lt;#if user_data.os==&quot;IOS&quot;&gt;act-ios</code></p><p>If you don&#39;t have two different tags for iOS and Android, then it will look simpler:</p><p><code>https://ad.doubleclick.net/ddm/s2s/appactivity/src=6637276;cat=act-tag;type=sales;ord=${ (id)! }</code></p><p><em>[Image: 1300]</em></p><h2 id="setup-2-seeing-data-in-branch-postbacks-to-ad-partners" tabindex="-1">Setup 2: Seeing data in Branch, postbacks to ad partners <a class="header-anchor" href="#setup-2-seeing-data-in-branch-postbacks-to-ad-partners" aria-label="Permalink to &quot;Setup 2: Seeing data in Branch, postbacks to ad partners&quot;">​</a></h2><h3 id="create-ad-link" tabindex="-1">Create ad link <a class="header-anchor" href="#create-ad-link" aria-label="Permalink to &quot;Create ad link&quot;">​</a></h3><p>If you&#39;re looking to see data in the Branch dashboard and postback to ad partners, create an ad link for the relevant partner, and then use that link in the click tracking URL field of your DCM creative tag.</p><div class="warning custom-block"><p class="custom-block-title">Server-side vs Client-side Handling</p><p>If a placement&#39;s <code>click</code> is handled <em>server-side</em> by a specific publisher and there is no <a href="./branch-universal-ads-advanced.html">device ID macro</a>, Branch will record clicks but not attribute downstream events in Branch&#39;s dashboard (client-side clicks will attribute downstream events in Branch&#39;s dashboard). Clicks with a device ID macro or client-side handling will attribute downstream events in Branch. Please contact <a href="mailto:integrations@branch.io" target="_blank" rel="noreferrer">integrations@branch.io</a> or contact your Account Manager for details on specific networks before implementation.</p></div>',38)])])}const g=t(n,[["render",i]]);export{u as __pageData,g as default};
